import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicThreeOnes() {
        // [1,1,1] k=2: subarrays [1,1] at 0-1 and 1-2
        assertEquals(2, new Solution().subarraySumCount(new int[]{1, 1, 1}, 2));
    }

    @Test
    void withNegativesKZero() {
        // [1,-1,0] k=0: [1,-1], [0], [1,-1,0] → 3 subarrays
        assertEquals(3, new Solution().subarraySumCount(new int[]{1, -1, 0}, 0));
    }

    @Test
    void emptyArray() {
        assertEquals(0, new Solution().subarraySumCount(new int[]{}, 0));
    }

    @Test
    void singleElementMatch() {
        assertEquals(1, new Solution().subarraySumCount(new int[]{3}, 3));
    }

    @Test
    void singleElementNoMatch() {
        assertEquals(0, new Solution().subarraySumCount(new int[]{3}, 5));
    }

    @Test
    void negativePrefixSeedRequired() {
        // [-1,-1,1] k=-1: [-1] at idx0, [-1] at idx1, full array [-1,-1,1]=-1 → 3
        // Without seeding {0:1} the full-array subarray would be missed
        assertEquals(3, new Solution().subarraySumCount(new int[]{-1, -1, 1}, -1));
    }

    @Test
    void longerMixedArray() {
        // [1,2,3,-2,-1,4] k=3, prefix=[0,1,3,6,4,3,7]
        // subarrays: [1,2], [3], [2,3,-2], [1,2,3,-2,-1], [-1,4] → 5
        assertEquals(5, new Solution().subarraySumCount(new int[]{1, 2, 3, -2, -1, 4}, 3));
    }
}
